                    else encoded_ctrl_words <= 56'h0000000;
                end
                8'b11110001: begin
                    if ({encoder_data_in[63:32], encoder_data_in[7:0]} == 40'h070707079C) encoded_ctrl_words <= {7'h00, 7'h00, 7'h00, 7'h00, encoder_data_in[31:8], 4'b1111};
                    else encoded_ctrl_words <= 56'h0000000;
                end
                8'b00010001: begin
                    if ({encoder_data_in[39:32], encoder_data_in[7:0]} == 16'h9C9C) encoded_ctrl_words <= {encoder_data_in[63:40], 8'hFF, encoder_data_in[31:8]};
                    else if ({encoder_data_in[39:32], encoder_data_in[7:0]} == 16'hFB9C) encoded_ctrl_words <= {encoder_data_in[63:40], 8'h0F, encoder_data_in[31:8]};
                    else encoded_ctrl_words <= 56'd0;
                end
                default: encoded_ctrl_words <= 56'd0;
            endcase
        end
    end

    always @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            sync_ctrl_word <= 2'b00;
            type_field <= 8'b0;
        end else begin
            if (encoder_control_in != 8'b00000000)
                sync_ctrl_word <= 2'b10;
            type_field <= get_output(encoder_data_in, encoder_control_in);
        end
    end

    always_comb begin
        if (|encoder_control_in)
            encoder_data_out = {sync_ctrl_word, type_field, encoded_ctrl_words};
        else
            encoder_data_out = {sync_word, encoded_data};
    end

endmodule

output.rtl/priority_encoder.v:
module priority_encoder_8x3 (
  input wire [7:0] in,
  output logic [2:0] out
);

  always_comb begin
    case (in)
      8'hFF: out = 3'b111; // Bit 7 is high, so we output 3'b111 regardless of the other bits.
      8'hFE: out = 3'b110;
      8'hFD: out = 3'b101;
      8'hFC: out = 3'b100;
      8'hFB: out = 3'b011;
      8'hFA: out = 3'b010;
      8'hF9: out = 3'b001;
      8'hF8: out = 3'b000;
      default: out = 3'b000; // Default to 3'b000 if none of the input lines are active.
    endcase
  end

endmodule

input.rtl/priority_encoder.v:
module priority_encoder_8x3 (
    input       [7:0] in      ,   // 8 input lines
    output reg  [2:0] out         // 3 output lines
);

always @(*) begin
    if (in[7])
        out = 3'b111;
    else if (in[6])
        out = 3'b110;
    else if (in[5])
        out = 3'b101;
    else if (in[4])
        out = 3'b100;
    else if (in[3])
        out = 3'b011;
    else if (in[2])
        out = 3'b010;
    else if (in[1])
        out = 3'b001;
    else if (in[0])
        out = 3'b000;
    else
        out = 3'b000; // Default case when no inputs are active
end

endmodule

output.rtl/cascaded_encoder.v:
module cascaded_encoder (
    input        [N-1:0] input_signal,    // N-bit wide input signal to be encoded
    output reg   [M-1:0] out,              // M-bit wide output vector that represents the index of the highest-priority active input
    output reg   [M-2:0] out_upper_half, // M-1 bit wide output vector that represents the index of the highest-priority active input of the most significant half of data
    output reg   [M-2:0] out_lower_half    // M-1 bit wide output vector that represents the index of the highest-priority active input of the least significant half of data
);

// Number of bits in the input
parameter N = 8;
// Width of the output vector
parameter M = $clog2(N);

reg [M-1:0] upper_half;
reg [M-1:0] lower_half;

priority_encoder #(.N(N/2),.M($clog2(N/2))) encoder_upper_half (
   .input_signal(input_signal[N/2-1:0]),
   .out(upper_half)
);

priority_encoder #(.N(N/2),.M($clog2(N/2))) encoder_lower_half (
   .input_signal(input_signal[N/2-2:0]),
   .out(lower_half)
);

assign out = (upper_half > lower_half)? upper_half : lower_half;
assign out_upper_half = (upper_half > lower_half)? upper_half : lower_half + M/2;
assign out_lower_half = (upper_half > lower_half)? upper_half + M/2 : lower_half;

endmodule

