output.rtl/fir_filter.sv:
module fir_filter (
    input logic clk,                 // Clock signal
    input logic reset,               // Reset signal
    input logic signed [15:0] input_sample,  // Input data sample
    output logic signed [15:0] output_sample, // Output filtered sample
    input logic signed [15:0] coeff0, // Coefficient for current input sample
    input logic signed [15:0] coeff1, // Coefficient for first delay
    input logic signed [15:0] coeff2, // Coefficient for second delay
    input logic signed [15:0] coeff3  // Coefficient for third delay
);

    // Declare internal storage for delay elements and accumulation
    logic signed [15:0] sample_delay1, sample_delay2, sample_delay3;
    logic signed [31:0] accumulator;

    // Sequential block to handle operations on clock or reset
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset state: Clear all registers and output
            sample_delay1 <= 16'd0;
            sample_delay2 <= 16'd0;
            sample_delay3 <= 16'd0;
            accumulator <= 32'd0;
            output_sample <= 16'd0;
        end else begin
            // Regular operation: Shift samples, compute filtered output
            sample_delay1 <= sample_delay2;
            sample_delay2 <= sample_delay3;
            sample_delay3 <= input_sample;
            accumulator <= accumulator + ((coeff0 * input_sample) + (coeff1 * sample_delay1) + (coeff2 * sample_delay2) + (coeff3 * sample_delay3));
            output_sample <= accumulator[15:0];
        end
    end

endmodule

module fir_filter (
    input wire clk,                  // Clock signal
    input wire reset,                // Asynchronous reset
    input wire [15:0] data_in,       // Input data
    output reg [15:0] data_out,      // Filtered output data
    input wire [1:0] window_type     // Window type selector: 0-Rectangular, 1-Hanning, 2-Hamming, 3-Blackman
);

    reg [15:0] coeff0, coeff1, coeff2, coeff3, coeff4, coeff5, coeff6, coeff7;
    reg [15:0] shift_reg0, shift_reg1, shift_reg2, shift_reg3, shift_reg4, shift_reg5, shift_reg6, shift_reg7;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            shift_reg0 <= 16'd0;
            shift_reg1 <= 16'd0;
            shift_reg2 <= 16'd0;
            shift_reg3 <= 16'd0;
            shift_reg4 <= 16'd0;
            shift_reg5 <= 16'd0;
            shift_reg6 <= 16'd0;
            shift_reg7 <= 16'd0;

            coeff0 <= 16'd10;
            coeff1 <= 16'd12;
            coeff2 <= 16'd12;
            coeff3 <= 16'd12;
            coeff4 <= 16'd12;
            coeff5 <= 16'd12;
            coeff6 <= 16'd12;
            coeff7 <= 16'd12;
        end else begin
            shift_reg0 <= shift_reg1;
            shift_reg1 <= shift_reg2;
            shift_reg2 <= shift_reg3;
            shift_reg3 <= shift_reg4;
            shift_reg4 <= shift_reg5;
            shift_reg5 <= shift_reg6;
            shift_reg6 <= shift_reg7;
            shift_reg7 <= data_in;

            case(window_type)
                2'b00: begin
                    coeff0 <= 16'd10;
                    coeff1 <= 16'd12;
                    coeff2 <= 16'd12;
                    coeff3 <= 16'd12;
                    coeff4 <= 16'd12;
                    coeff5 <= 16'd12;
                    coeff6 <= 16'd12;
                    coeff7 <= 16'd12;
                end
                2'b01: begin
                    coeff0 <= 16'd2;
                    coeff1 <= 4;
                    coeff2 <= 8;
                    coeff3 <= 12;
                    coeff4 <= 12;
                    coeff5 <= 8;
                    coeff6 <= 4;
                    coeff7 <= 2;
                end
                2'b10: begin
                    coeff0 <= 16'd3;
                    coeff1 <= 6;
                    coeff2 <= 9;
                    coeff3 <= 11;
                    coeff4 <= 11;
                    coeff5 <= 9;
                    coeff6 <= 6;
                    coeff7 <= 3;
                end
                2'b11: begin
                    coeff0 <= 16'd1;
                    coeff1 <= 2;
                    coeff2 <= 5;
                    coeff3 <= 9;
                    coeff4 <= 9;
                    coeff5 <= 5;
                    coeff6 <= 2;
                    coeff7 <= 1;
                end
            endcase

            data_out <= (coeff0 * shift_reg0) + (coeff1 * shift_reg1) +
                        (coeff2 * shift_reg2) + (coeff3 * shift_reg3) +
                        (coeff4 * shift_reg4) + (coeff5 * shift_reg5) +
                        (coeff6 * shift_reg6) + (coeff7 * shift_reg7) >>> 4;
        end
    end

endmodule

input.rtl/glitch_free_mux.sv:
module glitch_free_mux
(
    input clk1,		//input clk1
    input clk2,		// input clk2
    input rst_n,	// async reset
    input sel,		// selection line
    output  clkout	// clock output
);

reg clkout_reg ;
reg clk1_enable, clk2_enable;
reg clk1_out, clk2_out ;


// CLK1 ENABLE LOGIC
always@(posedge clk1 or negedge rst_n  ) begin
        if (~rst_n) begin
            clk1_enable <= 0 ; 
        end else begin
            clk1_enable <= ~ clk2_enable & ~sel  ;
        end 
end

// CLK2 ENABLE LOGIC
always@(posedge clk2 or negedge rst_n  ) begin
       if (~rst_n) begin
           clk2_enable <= 0 ; 
       end else begin
           clk2_enable <= ~ clk1_enable & sel  ;
       end 
end

// OUTPUT LOGIC
assign clkout = (clk1 & clk1_enable) | (clk2 & clk2_enable) ;

endmodule

