            o_use_powder    = 1'b0;
            o_heat_water    = 1'b1;
            o_pour_coffee   = 1'b0;
        end
        POUR: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b1;
        end
        default: begin
            o_bean_sel      = {NS_BEANS{1'b0}};
            o_grind_beans   = 1'b0;
            o_use_powder    = 1'b0;
            o_heat_water    = 1'b0;
            o_pour_coffee   = 1'b0;
        end
    endcase
end

