   assign data_out[39:20] = dbi_cntrl[0]? ~group_1 : group_1;
   assign data_out[19:0]  = dbi_cntrl[1]? ~group_0 : group_0;

   // Reset behavior
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         data_out <= 40'h00_0000_0000;
      end else begin
         data_out <= data_out;
      end
   end

endmodule

