module elastic_buffer_pattern_matcher #(
   parameter WIDTH  = 16,
   parameter ERR_TOLERANCE  = 2
   )(
   input                         clk     , // clock input
   input                         rst     , // Active high synchronous reset
   input         [WIDTH-1:0]     i_data  , // input data to be matched
   input         [WIDTH-1:0]     i_pattern, // pattern to be matched against
   output logic                  o_match    // output indicating a match between the pattern and i_data.
);

   // Define internal variables
   logic [WIDTH-1:0]          xor_data ; // Result of XOR operation between i_data and i_pattern
   logic [ERR_TOLERANCE:0]    err_count; // Number of bits that are mismatched
   logic                        match    ; // Final output indicating a match or mismatch

   // Matching logic
   always_comb begin
      // Calculate the XOR result between i_data and i_pattern
      xor_data = i_data ^ i_pattern;

      // Calculate the number of errors based on the error tolerance
      err_count = $countones(xor_data) - 1;

      // Determine if there is an error
      match = (err_count <= ERR_TOLERANCE);
   end

   // Set the final output
   assign o_match = match;

endmodule

input.rtl/elastic_buffer_pattern_matcher.sv:
module elastic_buffer_pattern_matcher #(
    parameter int WIDTH        = 16,                              // Represents the Width of the input data,pattern and mask signals.
    parameter int NUM_PATTERNS = 4
)(
    input  logic                              clk,                // Clock input
    input  logic                              rst,                // Active high synchronous reset
    input logic                               i_valid,            // Input data valid signal
    input  logic [WIDTH:0]                  i_data,             // Input data to be matched
    // Flattened array of patterns: each pattern is WIDTH bits wide.
    input  logic [NUM_PATTERNS*WIDTH:0]     i_pattern,          
    // Flattened array of masks: each mask is WIDTH bits wide (1 = compare; 0 = don't care).
    input  logic [NUM_PATTERNS*WIDTH:0]     i_mask,             
    input  logic [$clog2(WIDTH+1)-1:0]        i_error_tolerance,  // Runtime configurable error tolerance
     output logic                              o_valid,            // Output valid signal
    output logic [NUM_PATTERNS-1:0]           o_match             // Match output for each pattern
);
   logic [1:0] o_valid_reg;
   // ---------------------------------------------------------------------------
   // Pipeline Stage 1: Compute Masked Differences
   //
   // For each pattern, compute the bitwise difference between i_data and
   // the corresponding pattern slice, then mask off "don't care" bits.
   //---------------------------------------------------------------------------
   logic [WIDTH-1:0] diff_pipe1 [NUM_PATTERNS-1:0];
   logic [WIDTH-1:0] diff_pipe2 [NUM_PATTERNS-1:0];

   always_ff @(posedge clk) begin
      if (rst) begin
         for (int j = 0; j < NUM_PATTERNS; j++) begin
            diff_pipe1[j] <= '0;
         end
      end else begin
         for (int j = 0; j < NUM_PATTERNS; j++) begin
            // Extract the j-th pattern and mask slice from the flattened inputs.
            diff_pipe1[j] <= (i_data ^ i_pattern[j*WIDTH +: WIDTH]) & i_mask[j*WIDTH +: WIDTH];
         end
      end
   end

   //---------------------------------------------------------------------------
   // Pipeline Stage 2: Count Mismatches Using a Popcount Function
   //
   // Count the number of 1's (mismatches) in each diff vector.
   //---------------------------------------------------------------------------
   logic [$clog2(WIDTH+1)-1:0] error_count_pipe2 [NUM_PATTERNS-1:0];
   logic [$clog2(WIDTH+1)-1:0] error_count_pipe3 [NUM_PATTERNS-1:0];

   // Popcount function: counts the number of '1's in a vector.
   function automatic [$clog2(WIDTH+1)-1:0] popcount(input logic [WIDTH-1:0] vector);
      int k;
      popcount = 0;
      for (k = 0; k < WIDTH; k++) begin
         popcount += {{$clog2(WIDTH+1)-1{1'b0}}, vector[k]};
      end
   endfunction

   always_ff @(posedge clk) begin
      if (rst) begin
         for (int j = 0; j < NUM_PATTERNS; j++) begin
            error_count_pipe2[j] = '0;
			i_mask[j] <= '0;
   o_match[j] <= '0;
         end
      end else begin
         for (int j = 0; j < NUM_PATTERNS; j++) begin
            error_count_pipe2[j] <= popcount(diff_pipe1[j]);
         end
      end
   end

   //---------------------------------------------------------------------------
   // Pipeline Stage 3: Compare Error Count with Runtime Tolerance
   //
   // Assert the match signal for each pattern if the number of mismatches is
   // less than or equal to the error tolerance.
   //---------------------------------------------------------------------------
   always_comb begin
      for (int j = 0; j < NUM_PATTERNS; j++) begin
		o_match[j] = (error_count_pipe2[j] <= i_error_tolerance);
      end
   end


   //---------------------------------------------------------------------------
   // Valid pipeline
   //---------------------------------------------------------------------------
   always_ff @(posedge clk) begin
      if (rst)
         {o_valid, o_valid_reg} <= '0;
      else
         {o_valid, o_valid_reg} <= {o_valid_reg, i_valid}; 
   end

endmodule

input.rtl/elevator_control_system.sv:
/*
 * Elevator Control System
 * 
 * This module implements an FSM-based elevator control system capable of managing multiple floors,
 * handling call requests, and responding to emergency stops. The elevator transitions between 
 * five main states: Idle, Moving Up, Moving Down, Emergency Halt, Door Open. It prioritizes floor requests 
 * based on direction, moving to the highest or lowest requested floor depending on the current direction.
*/
module elevator_control_system #(
    parameter N = 8, //Number of floors
    parameter DOOR_OPEN_TIME_MS = 500 // Door open time in milliseconds
) ( 
    input wire clk,                   // 100MHz clock input
    input wire reset,                 // Active-high reset signal
    input wire [N-1:0] call_requests, // External Floor call requests
    input wire emergency_stop,        // Emergency stop signal
    output wire [$clog2(N)-1:0] current_floor, // Current floor of the elevator
    output reg direction,             // Elevator direction: 1 = up, 0 = down
    output reg door_open,             // Door open signal
    output reg [2:0] system_status    // Elevator system state indicator
);

// State Encoding
localparam IDLE = 3'b000;          // Elevator is idle
localparam MOVING_UP = 3'b001;     // Elevator moving up
localparam MOVING_DOWN = 3'b010;   // Elevator moving down
localparam EMERGENCY_HALT = 3'b011;// Emergency halt state
localparam DOOR_OPEN = 3'b100;     // Door open state

// Internal registers
reg [N-1:0] call_requests_internal;   // Internal copy of call requests
reg [2:0] present_state, next_state; // FSM current and next states
reg [$clog2(N)-1:0] max_request;     // Highest requested floor
reg [$clog2(N)-1:0] min_request;    // Lowest requested floor


// Door open time configuration
`ifdef SIMULATION
    localparam CLK_FREQ_MHZ = 100;  // Clock frequency in MHz
    localparam SIM_DOOR_OPEN_TIME_MS = 0.05; // Shorter door open time for simulation
    localparam DOOR_OPEN_CYCLES = (SIM_DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000); // Door open cycles for simulation   
`else
    // Calculating door open cycles based on time and clock frequency
    localparam CLK_FREQ_MHZ = 100;  // Clock frequency in MHz
    localparam DOOR_OPEN_CYCLES = (DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000);   // Door open cycles for real implementation
`endif


reg [$clog2(DOOR_OPEN_CYCLES)-1:0] door_open_counter;   // Counter for door open duration


reg [$clog2(N)-1:0] current_floor_reg, current_floor_next=0;

assign current_floor = current_floor_reg;

// FSM state transition
always@(posedge clk or posedge reset) begin
    if(reset)begin
        present_state <= IDLE;
        system_status <= IDLE;
        current_floor_reg <= 0;
        max_request <= 0;
        min_request <= N-1;        
    end else begin
        present_state <= next_state;
        system_status <= next_state;
        current_floor_reg <= current_floor_next;

        // Calculate max_request and min_request based on active requests
        max_request = 0;
        min_request = N-1;
        for (integer i = 0; i < N; i = i + 1) begin
            if (call_requests_internal[i]) begin
                if (i > max_request) max_request = i;
                if (i < min_request) min_request = i;
            end
        end
    end
end

always@(*)begin
    next_state = present_state;
    current_floor_next = current_floor_reg;

    case(present_state)
        IDLE:begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal != 0)begin
                if(max_request > current_floor_reg)begin
                    next_state = MOVING_UP;
                end else if(min_request < current_floor_reg) begin
                    next_state = MOVING_DOWN;
                end
            end
        end

        MOVING_UP: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg+1]) begin
                current_floor_next = current_floor_reg + 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg >= max_request) begin
                // If we reach the highest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg + 1;
                next_state = MOVING_UP;
            end
        end

        MOVING_DOWN: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg-1]) begin
                current_floor_next = current_floor_reg - 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg <= min_request) begin
                // If we reach the lowest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg - 1;
                next_state = MOVING_DOWN;
            end
        end

        EMERGENCY_HALT: begin
            if (!emergency_stop) begin
                next_state = IDLE;
                current_floor_next = 0; // Optionally reset to ground floor
            end
        end

        DOOR_OPEN: begin
            if (door_open_counter == 0) begin
                next_state = IDLE;
            end else begin
                next_state = DOOR_OPEN;
            end
        end
    endcase
end


// Door open control logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        door_open_counter <= 0;
        door_open <= 0;
    end else begin
        if (present_state == DOOR_OPEN) begin
            if (door_open_counter > 0) begin
                door_open <= 1;
                door_open_counter <= door_open_counter - 1;
            end else begin
                door_open <= 0;
                next_state = IDLE;
            end
        end else begin
            door_open <= 0;
            door_open_counter <= DOOR_OPEN_CYCLES; // Reset door open counter
        end
    end
end

// Call request management
always@(*)begin
    if(reset) begin
        call_requests_internal = 0;
    end else begin
        if(call_requests_internal[current_floor_reg])begin
            call_requests_internal[current_floor_reg] = 0;      // Clear served request
        end
        call_requests_internal = call_requests_internal | call_requests;    // Update requests
    end
end

// Direction control logic
always@(*)begin
    if(reset) begin
        direction = 1;  // Default direction is up
    end else begin
        if(present_state == MOVING_UP)begin
            direction = 1;
        end else if (present_state == MOVING_DOWN) begin
            direction = 0;
        end else begin
            direction = 1;
        end
    end
end

endmodule

