module FILO_RTL #(parameter DATA_WIDTH = 8,
                    parameter FIFO_DEPTH = 16)(
    // Inputs
    input clk,
    input rst,
    input push,
    input pop,
    input [DATA_WIDTH-1:0] data_in,

    // Outputs
    output logic [DATA_WIDTH-1:0] data_out,
    output logic full,
    output logic empty);

    // Internal signals
    reg [DATA_WIDTH-1:0] mem[FIFO_DEPTH];
    reg [7:0] top;

    always @(posedge clk or posedge rst) begin
        if(rst) begin
            top <= 0;
            full <= 0;
            empty <= 1;
        end else begin
            if(push &&!full) begin
                mem[top] <= data_in;
                top <= top + 1;
                full <= (top == FIFO_DEPTH - 1)? 1 : 0;
                empty <= (top == 0)? 1 : 0;
            end

            if(pop &&!empty) begin
                data_out <= mem[top];
                top <= top - 1;
                empty <= (top == 0)? 1 : 0;
            end
        end
    end
endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

