    );


    //////////////////////////////////////////////
    // Stage 7: F6 = 2 - D12, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F6 = TWO - D12;
    end

    assign D13 = F6 * D12;
    assign N13 = F6 * N12;

    reg18 reg_divisor_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D13[26:9]),
        .data_out(D14)
    );
    reg18 reg_dividend_stage8(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N13[26:9]),
        .data_out(N14)
    );

    dff1 ff10(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st8),
        .q     (st9)
    );


    //////////////////////////////////////////////
    // Stage 8: F7 = 2 - D14, multiply, register
    //////////////////////////////////////////////
    always_comb begin
