    //////////////////////////////////////////////
    always_comb begin
        F8 = TWO - D16;
    end

    assign D17 = F8 * D16;
    assign N17 = F8 * N16;

    reg18 reg_divisor_stage10(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D17[26:9]),
