   .rst           (rst),
   .A             (gcd_ab),
   .B             (gcd_bc),
   .go            (go_abc),
   .OUT           (OUT),
   .done          (done)
);

always_ff @ (posedge clk) begin
   if (rst) begin
      done_ab_latched    <= 0;
      done_bc_latched    <= 0;
