module lcm_3_ip #(
   parameter WIDTH = 4                    // Input bit-width
   )(
   input                         clk,
   input                         rst,
   input  [WIDTH-1:0]            A,
   input  [WIDTH-1:0]            B,
   input  [WIDTH-1:0]            C,
   input                         go,
   output logic  [3 * WIDTH-1:0] OUT,   // Updated output width
   output logic                  done
);

   logic [2*WIDTH-1:0]      gcd_result;     // GCD result
   logic [3*WIDTH-1:0]      product;        // Intermediate product
   logic                    gcd_done;
   logic                    product_ready;
   logic [2*WIDTH-1:0]      A_int;
   logic [2*WIDTH-1:0]      B_int;
   logic [2*WIDTH-1:0]      C_int;

   always_comb begin
      A_int = A*B;
      B_int = B*C;
      C_int = C*A;
   end

   // Calculate GCD of A, B, and C
   gcd_3_ip #(
      .WIDTH(2*WIDTH)
   ) gcd_inst (
      .clk   (clk),
      .rst   (rst),
      .A     (A_int),
      .B     (B_int),
      .C     (C_int),
      .go    (go),
      .OUT   (gcd_result),
      .done  (gcd_done)
   );

   // Sequential logic for LCM computation
   always_ff @(posedge clk) begin
      if (rst) begin
         OUT <= 0;
         done <= 0;
         product_ready <= 0;
      end else begin
         if (gcd_done) begin
            // Compute |A * B * C|
            product <= A * B * C;
            product_ready <= 1;
         end

         if (product_ready) begin
            // Compute LCM = |A * B * C| / GCD
            OUT <= product / gcd_result;
            done <= 1;
            product_ready <= 0;
         end else begin
            done <= 0;
         end
      end
   end
endmodule

module gcd_3_ip #(
   parameter WIDTH = 4
   )(
   input                     clk,
   input                     rst,
   input  [WIDTH-1:0]        A,
   input  [WIDTH-1:0]        B,
   input  [WIDTH-1:0]        C,
   output                    go,
   output logic  [WIDTH-1:0] OUT,
   output logic              done
);

logic [WIDTH-1:0] gcd_ab;
logic [WIDTH-1:0] gcd_bc;
logic             go_abc;
logic             done_ab;
logic             done_bc;
logic             done_ab_latched;
logic             done_bc_latched;

// GCD is calculated for AB and BC in parallel. The GCD for two numbers is lower than the numbers themselves in most cases.
// And calculating GCD for smaller numbers is comparatively faster using the implemented algorithm.
// Hence in order to reduce GCD computation latency the calculation is broken up in this fashion.

gcd_top
#( .WIDTH(WIDTH)
) gcd_A_B_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (A),
   .B             (B),
   .go            (go),
   .OUT           (gcd_ab),
   .done          (done_ab)
);

gcd_top
#( .WIDTH(WIDTH)
) gcd_B_C_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (B),
   .B             (C),
   .go            (go),
   .OUT           (gcd_bc),
   .done          (done_bc)
);

gcd_top
#( .WIDTH(WIDTH)
) gcd_ABC_inst (
   .clk           (clk),
   .rst           (rst),
   .A             (gcd_ab),
   .B             (gcd_bc),
   .go            (go_abc),
   .OUT           (OUT),
   .done          (done)
);

always_ff @ (posedge clk) begin
   if (rst) begin
      done_ab_latched    <= 0;
      done_bc_latched    <= 0;
   end else begin
      if(done_ab) begin
         done_ab_latched <= done_ab;
      end else if (go_abc) begin
         done_ab_latched <= 0;
      end

      if(done_bc) begin
         done_bc_latched <= done_bc;
      end else if (go_abc) begin
         done_bc_latched <= 0;
      end
   end
end

assign go_abc = done_ab_latched & done_bc_latched;

endmodule

