    reg [7:0] rx_buffer = 0;
    reg [1:0] state = IDLE;

    always @(posedge gmii_rx_clk) begin
        case(state)
            IDLE: begin
                if (gmii_rx_dv) begin
                    state <= RECEIVING;
                end else begin
                    state <= IDLE;
                end
