                    state <= FINISHED;
                end
            end
            FINISHED: begin
                // Handle finished frame logic here
                state <= IDLE;
            end
        endcase
    end

    assign m_axis_tdata = rx_buffer;
    assign m_axis_tvalid = (state == RECEIVING);
    assign m_axis_tlast = (state == FINISHED);

