    logic frame_space;
    logic bit_counter;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    always_ff @(posedge clk_in or posedge reset_in.
    always_comb begin
        case (present_state)
