module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    reg [7:0] p_key;      // Internal security key
    wire [7:0] w_result;   // Internal operation result

    assign p_key = 8'dAA; // Default to 0xAA

    always @(posedge i_clk or posedge i_rst_b) begin
        if (i_rst_b == 1'b0) begin
            o_result <= 8'b0;
        end else begin
            if (i_key_in == p_key) begin
                case (i_opcode)
                    3'b000: o_result <= i_operand_a + i_operand_b;
                    3'b001: o_result <= i_operand_a - i_operand_b;
                    3'b010: o_result <= i_operand_a * i_operand_b;
                    3'b011: o_result <= i_operand_a & i_operand_b;
                    3'b100: o_result <= i_operand_a | i_operand_b;
                    3'b101: o_result <= ~i_operand_a;
                    3'b110: o_result <= i_operand_a ^ i_operand_b;
                    3'b111: o_result <= ~(i_operand_a ^ i_operand_b);
                    default: o_result <= 8'b0;
                endcase
            end else begin
                o_result <= 8'b0;
            end
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface (
  input logic [7:0] i_addr, // Target address for read or write operations
  input logic [7:0] i_data_in, // Data to be written during a write operation
  input logic [7:0] i_key_in, // Key provided by the initiator for operation authorization
  input logic i_read_write_enable, // Specifies the requested operation; 1 for read, 0 for write
  input logic i_capture_pulse, // Qualifies input capture for addr, data_in, key_in, and read_write_enable
  input logic i_reset_bar, // Asynchronous, active-low reset to initialize internal states and registers

  output logic [7:0] o_data_out, // Data output during a read operation, valid only if the input key matches the internal key
  output logic o_error // Asserted if the input key is incorrect and deserted if input key is correct
);

  // Internal parameters and signals
  parameter p_data_width = 8; // Configurable data width, default is 8 bits
  parameter p_addr_width = 8; // Configurable address width, default is 8 bits
  parameter p_configurable_key = 8'hAA; // Internal 8-bit key, default value is 8'hAA
  logic [7:0] internal_key; // Internal 8-bit key
  logic [7:0] internal_data; // Internal storage for data

  always_ff @(posedge i_capture_pulse) begin
    if (i_reset_bar == 1'b0) begin
      // Reset internal registers and outputs
      internal_key <= p_configurable_key;
      internal_data <= 8'b0;
      o_data_out <= 8'b0;
      o_error <= 1'b0;
    end else begin
      // Read operation
      if (i_read_write_enable == 1'b1) begin
        if (internal_key == i_key_in) begin
          o_data_out <= internal_data;
          o_error <= 1'b0;
        end else begin
          o_error <= 1'b1;
          o_data_out <= 8'b0;
        end
      end
      // Write operation
      if (i_read_write_enable == 1'b0) begin
        if (internal_key == i_key_in) begin
          internal_data <= i_data_in;
          o_error <= 1'b0;
        end else begin
          o_error <= 1'b1;
        end
      end
    end
  end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
  parameter int p_address_width = 8,
  parameter int p_data_width = 8,
  parameter bit[7:0] p_unlock_code_0 = 8'hAB,
  parameter bit[7:0] p_unlock_code_1 = 8'hCD
) (
  input  logic [p_address_width-1:0] i_addr,
  input  logic [p_data_width-1:0]    i_data_in,
  input  logic                         i_read_write_enable,
  input  logic                         i_capture_pulse,
  input  logic                         i_rst_n,
  output logic [p_data_width-1:0]    o_data_out
);

  // Unlock State Machine
  typedef enum { UNLOCKED, UNLOCKING } unlock_state_t;
  logic [7:0] addr_q;
  unlock_state_t unlock_state_q;
  assign o_data_out = (i_read_write_enable &&!i_capture_pulse)? 0 : i_data_in;

  always_ff @(posedge i_capture_pulse) begin
    if (i_rst_n == 0) begin
      addr_q <= 8'b0000000;
      unlock_state_q <= UNLOCKED;
    end else begin
      case (unlock_state_q)
        UNLOCKED: begin
          if (i_addr == 8'h00) begin
            if (i_data_in == p_unlock_code_0) begin
              addr_q <= 8'b0000000;
              unlock_state_q <= UNLOCKING;
            end else begin
              addr_q <= 8'b0000000;
              unlock_state_q <= UNLOCKED;
            end
          end else if (i_addr == 8'h01) begin
            if (i_data_in == p_unlock_code_1) begin
              addr_q <= 8'b0000000;
              unlock_state_q <= UNLOCKING;
            end else begin
              addr_q <= 8'b0000000;
              unlock_state_q <= UNLOCKED;
            end
          end else begin
            addr_q <= 8'b0000000;
            unlock_state_q <= UNLOCKED;
          end
        end
        UNLOCKING: begin
          if (i_addr == 8'h00 || i_addr == 8'h01) begin
            addr_q <= 8'b0000000;
            unlock_state_q <= UNLOCKED;
          end else begin
            addr_q <= 8'b0000000;
            unlock_state_q <= UNLOCKING;
          end
        end
        default: begin
          addr_q <= 8'b0000000;
          unlock_state_q <= UNLOCKED;
        end
      endcase
    end
  end

  always_comb begin
    if (i_read_write_enable &&!i_capture_pulse) begin
      if (i_addr == 8'h00) begin
        o_data_out = 8'h00;
      end else if (i_addr == 8'h01) begin
        o_data_out = 8'h00;
      end else if (addr_q == 8'h00) begin
        o_data_out = 8'h00;
      end else if (addr_q == 8'h01) begin
        o_data_out = 8'h00;
      end else begin
        o_data_out = 8'h00;
      end
    end else begin
      o_data_out = 8'h00;
    end
  end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Internal signals and registers
    reg [3:0] state;             // Current state of the FSM
    reg [3:0] count;              // Counter for the number of clock cycles
    reg [3:0] delay;              // Holds the 4-bit delay value
    reg [3:0] time_left;         // Remaining time left in the timer
    wire done;                   // Asserted high when the timer completes its delay

    // Define the FSM states
    enum {IDLE, CONFIGURE_DELAY, COUNTING, DONE} state_enum;

    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state <= IDLE;
            count <= 0;
            delay <= 0;
            time_left <= 0;
            done <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (i_data_in == 8'b1101) begin
                        state <= CONFIGURE_DELAY;
                    end
                end
                CONFIGURE_DELAY: begin
                    delay <= i_data_in[3:0];
                    state <= COUNTING;
                end
                COUNTING: begin
                    count <= count + 1;
                    if (count == ((delay + 1) * 1000)) begin
                        time_left <= delay;
                        state <= DONE;
                    end
                end
                DONE: begin
                    if (i_ack) begin
                        state <= IDLE;
                        done <= 1;
                    end
                end
            endcase
        end
    end

    assign o_processing = (state == COUNTING);
    assign o_time_left = time_left;
    assign o_completed = done;

endmodule

