    o_one_hot_out <= '0;
  end else begin
    // Perform the conversion based on the binary input.
    o_one_hot_out <= {{(OUTPUT_WIDTH - BINARY_WIDTH){1'b0}}, i_binary_in};
  end
end

endmodule

