module signedadder #(parameter DATA_WIDTH = 8)(
    input i_clk,
    input i_rst_n,
    input i_start,
    input i_enable,
    input i_mode,
    input i_clear,
    input [DATA_WIDTH-1:0] i_operand_a,
    input [DATA_WIDTH-1:0] i_operand_b,
    output reg [DATA_WIDTH-1:0] o_resultant_sum,
    output reg o_overflow,
    output reg o_ready,
    output reg [1:0] o_status
);

    parameter MIN_VALUE = -((2**DATA_WIDTH)-1);
    parameter MAX_VALUE = ((2**DATA_WIDTH)-1);

    reg [DATA_WIDTH-1:0] r_operand_a;
    reg [DATA_WIDTH-1:0] r_operand_b;
    reg [DATA_WIDTH-1:0] r_resultant_sum;
    reg r_sign_a;
    reg r_sign_b;
    reg r_sign_sum;
    reg r_overflow;
    reg r_ready;
    reg [1:0] r_state;

    always @(posedge i_clk) begin
        if (!i_rst_n) begin
            r_operand_a <= 0;
            r_operand_b <= 0;
            r_resultant_sum <= 0;
            r_sign_a <= 0;
            r_sign_b <= 0;
            r_sign_sum <= 0;
            r_overflow <= 0;
            r_ready <= 0;
            r_state <= 2'b00;
        end else begin
            case(r_state)
                2'b00: begin
                    if (i_enable && i_start) begin
                        r_operand_a <= i_operand_a;
                        r_operand_b <= i_operand_b;
                        r_sign_a <= (i_operand_a[DATA_WIDTH-1] == 1);
                        r_sign_b <= (i_operand_b[DATA_WIDTH-1] == 1);
                        r_sign_sum <= 0;
                        r_state <= 2'b01;
                    end
                end
                2'b01: begin
                    r_resultant_sum <= {r_sign_sum, i_operand_a} + {r_sign_b, i_operand_b};
                    if (r_resultant_sum[DATA_WIDTH]!= r_sign_sum || r_resultant_sum[DATA_WIDTH+1]!= r_sign_sum) begin
                        r_overflow <= 1;
                    end else begin
                        r_overflow <= 0;
                    }
                    if (i_clear) begin
                        r_operand_a <= 0;
                        r_operand_b <= 0;
                        r_sign_a <= 0;
                        r_sign_b <= 0;
                        r_sign_sum <= 0;
                        r_overflow <= 0;
                        r_ready <= 0;
                        r_state <= 2'b00;
                    end else begin
                        r_ready <= 1;
                        r_state <= 2'b10;
                    end
                end
                2'b10: begin
                    o_resultant_sum <= r_resultant_sum;
                    o_overflow <= r_overflow;
                    o_ready <= r_ready;
                    r_state <= 2'b11;
                end
                2'b11: begin
                    r_ready <= 0;
                    r_state <= 2'b00;
                end
            endcase
        end
    end

endmodule

output.rtl/spi_fsm.v:
module spi_fsm (
    input  wire         i_clk,       // System clock
    input  wire         i_rst_b,     // Active-low async reset
    input  wire [15:0]  i_data_in,   // Parallel 16-bit data to transmit
    input  wire         i_enable,    // Enable block
    input  wire         i_fault,     // Fault indicator
    input  wire         i_clear,     // Forces FSM to clear/idle

    output reg          o_spi_cs_b,  // SPI chip select (active-low)
    output reg          o_spi_clk,   // SPI clock
    output reg          o_spi_data,  // Serialized SPI data out
    output reg [4:0]    o_bits_left, // Bits left to transmit
    output reg          o_done,      // Single-cycle pulse when done or error
    output reg [1:0]    o_fsm_state  // FSM state for external monitoring
);

// Define FSM states
localparam IDLE = 2'b00;
localparam TRANSMIT = 2'b01;
localparam CLOCK_TOGGLE = 2'b10;
localparam ERROR = 2'b11;

// Register for FSM state
reg [1:0] fsm_state;

// Register for counting bits left to transmit
reg [4:0] bits_left;

// Register for storing the MSB of the data to be transmitted
reg [7:0] msb;

// Register for storing the LSB of the data to be transmitted
reg [7:0] lsb;

// Register for storing the received data
reg [7:0] received_data;

// Register for indicating if an error has occurred
reg error;

// Initial conditions
initial begin
    fsm_state <= IDLE;
    bits_left <= 16'd10;
    msb <= 8'd0;
    lsb <= 8'd0;
    received_data <= 8'd0;
    error <= 1'b0;
end

always @(posedge i_clk) begin
    case (fsm_state)
        IDLE: begin
            if (i_enable == 1'b1) begin
                o_spi_cs_b <= 1'b1;
                o_spi_clk <= 1'b0;
                o_spi_data <= 1'b0;
                o_bits_left <= 16'd10;
                fsm_state <= TRANSMIT;
            end else begin
                fsm_state <= IDLE;
            end
        end
        TRANSMIT: begin
            if (i_enable == 1'b1) begin
                o_spi_cs_b <= 1'b0;
                o_spi_clk <= 1'b1;
                o_spi_data <= i_data_in[7:0];
                bits_left <= bits_left - 1'b1;
                if (bits_left == 1'b0) begin
                    fsm_state <= CLOCK_TOGGLE;
                end
            end else begin
                fsm_state <= IDLE;
            end
        end
        CLOCK_TOGGLE: begin
            if (i_enable == 1'b1) begin
                o_spi_cs_b <= 1'b1;
                o_spi_clk <= 1'b0;
                o_spi_data <= 1'b0;
                if (received_data!= i_data_in) begin
                    error <= 1'b1;
                    fsm_state <= ERROR;
                end else begin
                    error <= 1'b0;
                    fsm_state <= IDLE;
                end
            end else begin
                fsm_state <= IDLE;
            end
        end
        ERROR: begin
            if (i_enable == 1'b1) begin
                o_spi_cs_b <= 1'b0;
                o_spi_clk <= 1'b0;
                o_spi_data <= 1'b0;
                fsm_state <= IDLE;
            end else begin
                fsm_state <= IDLE;
            end
        end
    endcase
end

endmodule

output.rtl/unique_number_identifier.v:
module unique_number_identifier #( 
    parameter p_bit_width = 8, 
    parameter p_max_numbers = 16 
)(
    input wire i_clk, 
    input wire i_rst_n, 
    input wire i_ready, 
    input wire [p_bit_width-1:0] i_number, 
    output reg [p_bit_width-1:0] o_unique_number 
);

// Unique Number Identifier Module
reg [p_bit_width-1:0] counter;
reg [p_bit_width-1:0] prev_number;
reg [p_bit_width-1:0] next_number;
reg [p_bit_width-1:0] unique_number;

always @(posedge i_clk) begin
    if (!i_rst_n) begin
        // Reset
        unique_number <= 0;
        counter <= 0;
        prev_number <= 0;
        next_number <= 0;
    end else begin
        // Detect ready signal
        if (i_ready) begin
            // Check if ready signal has been deserted
            if (counter == 0) begin
                // Update previous number
                prev_number <= i_number;
            end
            // Update next number
            next_number <= i_number;
            // Increment counter
            counter <= counter + 1;
        end
        // Check if counter equals max numbers
        if (counter == p_max_numbers) begin
            // Calculate unique number
            unique_number <= (prev_number ^ next_number);
            // Reset counter and previous number
            counter <= 0;
            prev_number <= 0;
        end
    end
end

assign o_unique_number = unique_number;

endmodule

