module pipelined_skid_buffer(
    input wire clock,
    input wire rst,

    input wire [3:0] data_i,
    input wire valid_i,
    output wire ready_o,
    output wire valid_o,
    output wire [3:0] data_o,
    input wire ready_i

    );    

logic [3:0] data_reg;
logic data_present;
logic buffer;

always_ff @(posedge clock) begin
    if (rst) begin
        data_present <= 0;
        buffer <= 0;
        data_reg <= 4'b0;
    end else begin
        if (valid_i &&!ready_i) begin
            data_present <= 1;
            buffer <= 1;
            data_reg <= data_i;
        end

        if (!valid_i && ready_i && buffer == 1) begin
            data_present <= 0;
            buffer <= 0;
        end
    end
end

assign valid_o = data_present && ready_i;
assign ready_o = data_present ||!valid_i;
assign data_o = data_present? data_reg : 4'b0;

endmodule

